[correct]

for(var i = 0; i <= 4; i++) pos[i][79].n.img = "wood_h";
for(var i = 0; i <= 4; i++) pos[i][58].n.img = "stone_h";
for(var i = 21; i <= 27; i++) pos[i][79].n.img = "stone";
pos[24][79].n.img = "stone";
pos[24][79].f.img = "wood";
pos[24][79].f.icon = 7;
pos[11][40].f.img = "wood";
pos[11][40].f.icon = 7;
pos[2][58].event = pos[2][79].event = 13;

[endmap]
;-------------------------------------------------------------------------------
; マップを開いた時に必ず実行されるスクリプト
[initial]

if(game.party.curX <= 16 && game.party.curY <= 20)
{
	monsters = [m.ハーピー];
	battleRate = 0.05;
}
else
{
	monsters = [m.スライム, m.オーク, m.ジャイアントバット, m.巨大ぐも, m.ローグ];
	battleRate = 0.005;
}
if(! loading) events.push2(15, 16);

[endinitial]
;===============================================================================
;◆イベント◆

; 初期発生イベント
events = [1, 3, 5, 6, 8, 9, 10, 11, 15, 16]

;-------------------------------------------------------------------------------
*event_1
;[exp] onObjectTrigger

@notice text="Seagull Village"

[eventoff]
;-------------------------------------------------------------------------------
*event_2
;[exp] true

@delevent
@jump storage="main03.scn" target=*trip_4

[eventoff]
;-------------------------------------------------------------------------------
*event_3
;[exp] onObjectTrigger

@question title="<y>Will you drink water from the gushing spring?" cancel=true
[if exp='tf.result']
	[if exp='f.fountainForOpeningEvent']
		@eval exp='o.噴水.doDamage = o.グランドヒール.doDamage'
		@eval exp='o.噴水.resultMessage = o.グランドヒール.resultMessage'
		@btcmd name=噴水
		@notice text="Party's HP restored!"
	[else]
		@notice text="I tried drinking it, but it was just water."
	[endif]
[endif]

[eventoff]
;-------------------------------------------------------------------------------
*event_4
;[exp] true

@delevent
@jump storage="main03.scn" target=*trip_5

[eventoff]
;-------------------------------------------------------------------------------
*event_5
;[exp] onObjectTrigger

@roadguide e="Sapphire City" s="Seagull Village"

[eventoff]
;-------------------------------------------------------------------------------
*event_6
;[exp] onObjectTrigger

@notice text="Be careful of bandits on the mountain pass ahead!"

[eventoff]
;-------------------------------------------------------------------------------
*event_7
;[exp] ! game.protectHeroines && o.ワイルド・ブル.interruption == 0 && random < 0.1

; ワイルド・ブルとの決闘
@jump storage="duel.ks" target=*wildbull_encounter

[eventoff]
;-------------------------------------------------------------------------------
*event_8
;[exp] onObjectTrigger

@notice text="Welcome to Sapphire City!"

[eventoff]
;-------------------------------------------------------------------------------
*event_9
;[exp] onObjectTrigger

@notice text="Wild Bull's Mansion"

[eventoff]
;-------------------------------------------------------------------------------
*event_10
;[exp] true

@delevent
@eval exp='o.ワイルド・ブルのアジトを探せ.flag ++'
@wait time=500 cond='WAY != "n"'
@walk turn=n cond='WAY != "n"'
@wait time=500
[texton]
[リーダー f=05]「This is...!」[k]
Deep in the woods stood a magnificent mansion. The sign posted on it read "Wild Bull's Mansion".[k]
[if exp='! game.isFreeMode']
	[テオ f=06]「Alex...! Their hideout is in a place like this...!」[k]
[endif]
Alex and his gang must be using this place as a base to do all sorts of evil.[k]
[textoff]
@se f=period
@notice text="<y>Found one Wild Bull hideout."

[eventoff]
;-------------------------------------------------------------------------------
*event_11
;[exp] onObjectTrigger

@question title="There is a stone monument. Would you like to touch it?"
[eventoff cond='! tf.result']
@se f=period
@eval exp='o.ランドン渓谷・崖上.setWarp(28, 9, "E", "warp")'
@eval exp='o.ランドン渓谷・崖上.setWarp(29, 71, "F", "warp")'
@delevent

[eventoff]
;-------------------------------------------------------------------------------
*event_12
;[exp] true

; ホーク・ウイングメンバーの襲撃
@delevent
@delevent num=13
@delevent num=14
@jump storage="main05.scn" target=*kobold_5

[eventoff]
;-------------------------------------------------------------------------------
*event_13
;[exp] party.lastIsMove

; イベント時の移動制限。ダンジョンに入れないようにする
[texton]
[テオ f=06]「We should go somewhere else.」[k]
[textoff]
@walk move=s

[eventoff]
;-------------------------------------------------------------------------------
*event_14
;[exp] party.lastIsMove && map.pos[26][66].f.warp !== void

; イベント時の移動制限。ダンジョンに入れないようにする
[texton]
[テオ f=06]「We should go somewhere else.」[k]
[textoff]
@walk move=n

[eventoff]
