;[exp] true

@monster pos=1 name=バルキリー naked=1
@monster pos=3 name=バルキリー naked=1
@monster pos=5 name=バルキリー naked=1
@monster pos=9 name=ウィッチ naked=1
@monster pos=11 name=ウィッチ naked=1
@callbattle normal=true

[eventoff]
