@monster pos=1 name=ブレイズマン naked=1
@monster pos=3 name=ブレイズマン naked=1
@monster pos=5 name=ブレイズマン naked=1
@monster pos=9 name=シューター naked=1
@monster pos=11 name=シューター naked=1
